const startMs = $('Start Timer').first().json.startMs;
const checks = [];
let allPassed = true;

try {
  const r = $('Check Fitness Service').first().json;
  const ok = !!(r?.status === 'ok' || r?.status === 'healthy' || r?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'fitness-service', ok, detail: r?.status ?? JSON.stringify(r).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'fitness-service', ok: false, detail: e.message });
}

try {
  const r = $('Check Fitness API').first().json;
  const payload = r?.body ?? r;
  const ok = !!(payload?.status === 'ok' || payload?.status === 'healthy' || payload?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'fitness-api', ok, detail: payload?.status ?? JSON.stringify(payload).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'fitness-api', ok: false, detail: e.message });
}

const durationMs = Date.now() - startMs;
return [{ json: {
  passed: allPassed,
  step: 'Fitness',
  statusCode: allPassed ? 200 : 503,
  details: checks.map(c => `${c.name}: ${c.ok ? 'OK' : 'FAIL'}`).join(' | '),
  durationMs,
  checks
} }];
